func (gs *GameServer) cmdSetRole(cmd Command) {
	if !gs.checkPermission(cmd.Sender, RoleAdmin) {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Content: "Permission denied. Admin role required.",
		})
		return
	}

	if len(cmd.Args) < 2 {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Content: "Usage: /setrole <username> <player|moderator|admin>",
		})
		return
	}

	targetName := cmd.Args[0]
	newRole := Role(strings.ToLower(cmd.Args[1]))

	if newRole != RolePlayer && newRole != RoleModerator && newRole != RoleAdmin {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Content: "Invalid role. Valid roles: player, moderator, admin",
		})
		return
	}

	target := gs.findPlayerByUsername(targetName)
	if target == nil {
		gs.sendMessage(cmd.Sender.Conn, ServerMessage{
			Type:    "error",
			Content: fmt.Sprintf("Player '%s' not found.", targetName),
		})
		return
	}

	oldRole := target.Role
	gs.mu.Lock()
	target.Role = newRole
	gs.mu.Unlock()

	log.Printf("[ADMIN] %s changed %s's role from %s to %s", cmd.Sender.Username, target.Username, oldRole, newRole)

	gs.sendMessage(target.Conn, ServerMessage{
		Type:    "system",
		Content: fmt.Sprintf("Your role has been changed to %s by %s.", newRole, cmd.Sender.Username),
	})

	gs.sendMessage(cmd.Sender.Conn, ServerMessage{
		Type:    "system",
		Content: fmt.Sprintf("Changed %s's role from %s to %s.", target.Username, oldRole, newRole),
	})
}

func (gs *GameServer) findPlayerByUsername(username string) *Player {
	gs.mu.RLock()
	defer gs.mu.RUnlock()

	for _, p := range gs.players {
		if strings.EqualFold(p.Username, username) {
			return p
		}
	}
	return nil
}

func (gs *GameServer) canActOn(sender, target *Player) bool {
	roleWeight := map[Role]int{
		RolePlayer:    0,
		RoleModerator: 1,
		RoleAdmin:     2,
	}
	return roleWeight[sender.Role] > roleWeight[target.Role]
}

func (gs *GameServer) sendMessage(conn net.Conn, msg ServerMessage) {
	data, err := json.Marshal(msg)
	if err != nil {
		log.Printf("Error marshaling message: %v", err)
		return
	}
	conn.Write(append(data, '\n'))
}

func (gs *GameServer) broadcast(msg ServerMessage, excludeID string) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()

	for id, p := range gs.players {
		if id != excludeID {
			gs.sendMessage(p.Conn, msg)
		}
	}
}

